              <Label htmlFor="password">Mot de passe</Label>
              <Input
                id="password"
                type="password"
                required
                value={formData.password}
                onChange={(e) =>
                  setFormData({ ...formData, password: e.target.value })
                }
                placeholder="••••••••"
              />
            </div>

            <Button
              type="submit"
              className="w-full bg-[#00A86B] hover:bg-[#008f5d]"
              disabled={isLoading}
